import{_ as a,o as r,c as e,a0 as n}from"./chunks/framework.Bmhw_dvp.js";const u=JSON.parse('{"title":"Agent 框架","description":"","frontmatter":{},"headers":[],"relativePath":"aiAgents/agent.md","filePath":"aiAgents/agent.md"}'),o={name:"aiAgents/agent.md"};function i(l,t,s,h,g,c){return r(),e("div",null,[...t[0]||(t[0]=[n('<h1 id="agent-框架" tabindex="-1">Agent 框架 <a class="header-anchor" href="#agent-框架" aria-label="Permalink to &quot;Agent 框架&quot;">​</a></h1><p>AI Agent 开发框架是构建智能体的核心基础设施，按类型分为<strong>编排框架</strong>、<strong>多 Agent 框架</strong>和<strong>低代码/无代码平台</strong>。</p><hr><h2 id="编排框架" tabindex="-1">编排框架 <a class="header-anchor" href="#编排框架" aria-label="Permalink to &quot;编排框架&quot;">​</a></h2><h3 id="langchain" tabindex="-1">LangChain <a class="header-anchor" href="#langchain" aria-label="Permalink to &quot;LangChain&quot;">​</a></h3><ul><li><strong>官网</strong>：<a href="https://www.langchain.com" target="_blank" rel="noreferrer">https://www.langchain.com</a></li><li><strong>文档</strong>：<a href="https://python.langchain.com" target="_blank" rel="noreferrer">https://python.langchain.com</a></li><li><strong>GitHub</strong>：<a href="https://github.com/langchain-ai/langchain" target="_blank" rel="noreferrer">https://github.com/langchain-ai/langchain</a></li><li><strong>语言</strong>：Python / JavaScript (TypeScript)</li></ul><p>业界最流行的 LLM 应用开发框架，提供链式调用、提示词管理、工具集成等核心能力。</p><hr><h3 id="langgraph" tabindex="-1">LangGraph <a class="header-anchor" href="#langgraph" aria-label="Permalink to &quot;LangGraph&quot;">​</a></h3><ul><li><strong>文档</strong>：<a href="https://langchain-ai.github.io/langgraph" target="_blank" rel="noreferrer">https://langchain-ai.github.io/langgraph</a></li><li><strong>GitHub</strong>：<a href="https://github.com/langchain-ai/langgraph" target="_blank" rel="noreferrer">https://github.com/langchain-ai/langgraph</a></li><li><strong>语言</strong>：Python / JavaScript</li></ul><p>LangChain 官方推出的图结构 Agent 编排框架，支持循环、条件分支等复杂工作流。</p><hr><h3 id="llamaindex" tabindex="-1">LlamaIndex <a class="header-anchor" href="#llamaindex" aria-label="Permalink to &quot;LlamaIndex&quot;">​</a></h3><ul><li><strong>官网</strong>：<a href="https://www.llamaindex.ai" target="_blank" rel="noreferrer">https://www.llamaindex.ai</a></li><li><strong>文档</strong>：<a href="https://docs.llamaindex.ai" target="_blank" rel="noreferrer">https://docs.llamaindex.ai</a></li><li><strong>GitHub</strong>：<a href="https://github.com/run-llama/llama_index" target="_blank" rel="noreferrer">https://github.com/run-llama/llama_index</a></li><li><strong>语言</strong>：Python / TypeScript</li></ul><p>专注于数据增强和检索（RAG）的框架，提供强大的索引和查询能力。</p><hr><h3 id="haystack" tabindex="-1">Haystack <a class="header-anchor" href="#haystack" aria-label="Permalink to &quot;Haystack&quot;">​</a></h3><ul><li><strong>官网</strong>：<a href="https://haystack.deepset.ai" target="_blank" rel="noreferrer">https://haystack.deepset.ai</a></li><li><strong>文档</strong>：<a href="https://docs.haystack.deepset.ai" target="_blank" rel="noreferrer">https://docs.haystack.deepset.ai</a></li><li><strong>GitHub</strong>：<a href="https://github.com/deepset-ai/haystack" target="_blank" rel="noreferrer">https://github.com/deepset-ai/haystack</a></li><li><strong>语言</strong>：Python</li></ul><p>开源 NLP 框架，专注于构建生产级的搜索和问答系统。</p><hr><h3 id="semantic-kernel" tabindex="-1">Semantic Kernel <a class="header-anchor" href="#semantic-kernel" aria-label="Permalink to &quot;Semantic Kernel&quot;">​</a></h3><ul><li><strong>官网</strong>：<a href="https://learn.microsoft.com/en-us/semantic-kernel" target="_blank" rel="noreferrer">https://learn.microsoft.com/en-us/semantic-kernel</a></li><li><strong>GitHub</strong>：<a href="https://github.com/microsoft/semantic-kernel" target="_blank" rel="noreferrer">https://github.com/microsoft/semantic-kernel</a></li><li><strong>语言</strong>：C# / Python / Java</li></ul><p>微软开源的 SDK，支持将 AI 服务与传统编程语言无缝集成。</p><hr><h2 id="多-agent-框架" tabindex="-1">多 Agent 框架 <a class="header-anchor" href="#多-agent-框架" aria-label="Permalink to &quot;多 Agent 框架&quot;">​</a></h2><h3 id="autogpt" tabindex="-1">AutoGPT <a class="header-anchor" href="#autogpt" aria-label="Permalink to &quot;AutoGPT&quot;">​</a></h3><ul><li><strong>官网</strong>：<a href="https://agpt.co" target="_blank" rel="noreferrer">https://agpt.co</a></li><li><strong>GitHub</strong>：<a href="https://github.com/Significant-Gravitas/AutoGPT" target="_blank" rel="noreferrer">https://github.com/Significant-Gravitas/AutoGPT</a></li><li><strong>语言</strong>：Python</li></ul><p>最早出圈的自主 Agent 项目，能够自动分解目标并迭代执行任务。</p><hr><h3 id="metagpt" tabindex="-1">MetaGPT <a class="header-anchor" href="#metagpt" aria-label="Permalink to &quot;MetaGPT&quot;">​</a></h3><ul><li><strong>官网</strong>：<a href="https://www.deepwisdom.ai" target="_blank" rel="noreferrer">https://www.deepwisdom.ai</a></li><li><strong>GitHub</strong>：<a href="https://github.com/geekan/MetaGPT" target="_blank" rel="noreferrer">https://github.com/geekan/MetaGPT</a></li><li><strong>语言</strong>：Python</li></ul><p>多 Agent 协作框架，模拟软件公司组织架构，可自动完成从需求到代码的完整流程。</p><hr><h3 id="crewai" tabindex="-1">CrewAI <a class="header-anchor" href="#crewai" aria-label="Permalink to &quot;CrewAI&quot;">​</a></h3><ul><li><strong>官网</strong>：<a href="https://www.crewai.com" target="_blank" rel="noreferrer">https://www.crewai.com</a></li><li><strong>文档</strong>：<a href="https://docs.crewai.com" target="_blank" rel="noreferrer">https://docs.crewai.com</a></li><li><strong>GitHub</strong>：<a href="https://github.com/joaomdmoura/crewAI" target="_blank" rel="noreferrer">https://github.com/joaomdmoura/crewAI</a></li><li><strong>语言</strong>：Python</li></ul><p>以角色扮演为核心的多 Agent 协作框架，配置简洁，适合快速原型开发。</p><hr><h3 id="microsoft-autogen" tabindex="-1">Microsoft AutoGen <a class="header-anchor" href="#microsoft-autogen" aria-label="Permalink to &quot;Microsoft AutoGen&quot;">​</a></h3><ul><li><strong>文档</strong>：<a href="https://microsoft.github.io/autogen" target="_blank" rel="noreferrer">https://microsoft.github.io/autogen</a></li><li><strong>GitHub</strong>：<a href="https://github.com/microsoft/autogen" target="_blank" rel="noreferrer">https://github.com/microsoft/autogen</a></li><li><strong>语言</strong>：Python / .NET</li></ul><p>微软开源的多 Agent 对话框架，支持 Agent 之间的对话协作和人工介入。</p><hr><h3 id="agentscope" tabindex="-1">AgentScope <a class="header-anchor" href="#agentscope" aria-label="Permalink to &quot;AgentScope&quot;">​</a></h3><ul><li><strong>GitHub</strong>：<a href="https://github.com/modelscope/agentscope" target="_blank" rel="noreferrer">https://github.com/modelscope/agentscope</a></li><li><strong>语言</strong>：Python</li></ul><p>阿里 ModelScope 团队开源的多 Agent 平台，支持分布式部署和丰富的交互模式。</p><hr><h2 id="低代码-无代码平台" tabindex="-1">低代码 / 无代码平台 <a class="header-anchor" href="#低代码-无代码平台" aria-label="Permalink to &quot;低代码 / 无代码平台&quot;">​</a></h2><h3 id="dify" tabindex="-1">Dify <a class="header-anchor" href="#dify" aria-label="Permalink to &quot;Dify&quot;">​</a></h3><ul><li><strong>官网</strong>：<a href="https://dify.ai" target="_blank" rel="noreferrer">https://dify.ai</a></li><li><strong>GitHub</strong>：<a href="https://github.com/langgenius/dify" target="_blank" rel="noreferrer">https://github.com/langgenius/dify</a></li><li><strong>语言</strong>：Python / TypeScript</li></ul><p>开源 LLM 应用开发平台，支持可视化编排、RAG、Agent 和工作流管理。</p><hr><h3 id="flowise" tabindex="-1">Flowise <a class="header-anchor" href="#flowise" aria-label="Permalink to &quot;Flowise&quot;">​</a></h3><ul><li><strong>官网</strong>：<a href="https://flowiseai.com" target="_blank" rel="noreferrer">https://flowiseai.com</a></li><li><strong>GitHub</strong>：<a href="https://github.com/FlowiseAI/Flowise" target="_blank" rel="noreferrer">https://github.com/FlowiseAI/Flowise</a></li><li><strong>语言</strong>：TypeScript</li></ul><p>基于 LangChain 的可视化低代码构建工具，通过拖拽节点即可搭建 AI 工作流。</p><hr><h3 id="coze-扣子" tabindex="-1">Coze / 扣子 <a class="header-anchor" href="#coze-扣子" aria-label="Permalink to &quot;Coze / 扣子&quot;">​</a></h3><ul><li><strong>官网</strong>：<a href="https://www.coze.com" target="_blank" rel="noreferrer">https://www.coze.com</a>（国际版）</li><li><strong>国内版</strong>：<a href="https://www.coze.cn" target="_blank" rel="noreferrer">https://www.coze.cn</a></li></ul><p>字节跳动推出的 AI Bot 开发平台，支持零代码搭建智能体并发布到多个渠道。</p><hr><h3 id="fastgpt" tabindex="-1">FastGPT <a class="header-anchor" href="#fastgpt" aria-label="Permalink to &quot;FastGPT&quot;">​</a></h3><ul><li><strong>官网</strong>：<a href="https://fastgpt.in" target="_blank" rel="noreferrer">https://fastgpt.in</a></li><li><strong>GitHub</strong>：<a href="https://github.com/labring/FastGPT" target="_blank" rel="noreferrer">https://github.com/labring/FastGPT</a></li><li><strong>语言</strong>：TypeScript</li></ul><p>开源知识库问答系统，支持可视化工作流编排和 RAG 检索增强。</p>',61)])])}const f=a(o,[["render",i]]);export{u as __pageData,f as default};
